import org.junit.jupiter.api.Test;

class UnionQueryEvaluationStepTest {

	@Test
	void evaluateAvoidsDualUnionIterationWhenRightStepReturnsRegularEmptyIteration() {
		BindingSet leftBinding = bindingSet("entity", "urn:condition");
		QueryEvaluationStep left = bindings -> new CloseableIteratorIteration<>(List.of(leftBinding).iterator());
		QueryEvaluationStep right = bindings -> new CloseableIteratorIteration<>(List.<BindingSet>of().iterator());
		UnionQueryEvaluationStep step = new UnionQueryEvaluationStep(left, right);

		try (CloseableIteration<BindingSet> iteration = step.evaluate(EmptyBindingSet.getInstance())) {
			assertThat(iteration).isNotInstanceOf(DualUnionIteration.class);
			assertThat(iteration).toIterable().containsExactly(leftBinding);
		}
	}

	@Test
	void evaluateAvoidsDualUnionIterationWhenLeftStepReturnsRegularEmptyIteration() {
		BindingSet rightBinding = bindingSet("entity", "urn:medication");
		QueryEvaluationStep left = bindings -> new CloseableIteratorIteration<>(List.<BindingSet>of().iterator());
		QueryEvaluationStep right = bindings -> new CloseableIteratorIteration<>(List.of(rightBinding).iterator());
		UnionQueryEvaluationStep step = new UnionQueryEvaluationStep(left, right);

		try (CloseableIteration<BindingSet> iteration = step.evaluate(EmptyBindingSet.getInstance())) {
			assertThat(iteration).isNotInstanceOf(DualUnionIteration.class);
			assertThat(iteration).toIterable().containsExactly(rightBinding);
		}
	}

	private static BindingSet bindingSet(String name, String value) {
		QueryBindingSet bindingSet = new QueryBindingSet();
		bindingSet.addBinding(name, SimpleValueFactory.getInstance().createIRI(value));
		return bindingSet;
	}
}
